import { describe, expect, it } from '@a0n/gnosis/test';

import {
  auditAgentSwarmCertificate,
  evaluateAgentSwarmContract,
  pathMatchesScope,
  type AgentSwarmContractRequest,
} from './agent-swarm-contract';

function createBaseRequest(): AgentSwarmContractRequest {
  return {
    changeId: 'pr-481',
    targetBranch: 'main',
    protectedBranch: true,
    riskLevel: 'standard',
    taskContracts: [
      {
        id: 'runtime-kernel',
        title: 'Update runtime contract kernel',
        owner: 'runtime',
        allowedPathScopes: ['open-source/gnosis/src/runtime/**'],
        allowedTools: ['apply_patch', 'pnpm:test'],
        requiredVerifications: ['gnosis:test'],
        allowPathOverlapWith: [],
        requiresTrace: true,
        requiresHumanReview: false,
      },
      {
        id: 'verification-mcp',
        title: 'Expose MCP surface',
        owner: 'mcp',
        allowedPathScopes: ['apps/verification-mcp/src/**'],
        allowedTools: ['apply_patch', 'pnpm:typecheck', 'pnpm:build'],
        requiredVerifications: ['verification-mcp:typecheck'],
        allowPathOverlapWith: [],
        requiresTrace: true,
        requiresHumanReview: true,
      },
    ],
    taskExecutions: [
      {
        taskId: 'runtime-kernel',
        agentId: 'agent-runtime-1',
        status: 'completed',
        touchedPaths: [
          'open-source/gnosis/src/runtime/agent-swarm-contract.ts',
        ],
        toolsUsed: ['apply_patch', 'pnpm:test'],
        traceId: 'trace-runtime-1',
        traceDigest: 'digest-runtime-1',
        verificationResults: [{ id: 'gnosis:test', status: 'passed' }],
        startedAt: '2026-04-10T12:00:00.000Z',
        finishedAt: '2026-04-10T12:01:00.000Z',
      },
      {
        taskId: 'verification-mcp',
        agentId: 'agent-mcp-1',
        status: 'completed',
        touchedPaths: ['apps/verification-mcp/src/handler.ts'],
        toolsUsed: ['apply_patch', 'pnpm:typecheck', 'pnpm:build'],
        traceId: 'trace-mcp-1',
        traceDigest: 'digest-mcp-1',
        verificationResults: [
          { id: 'verification-mcp:typecheck', status: 'passed' },
          { id: 'verification-mcp:build', status: 'passed' },
        ],
        startedAt: '2026-04-10T12:01:00.000Z',
        finishedAt: '2026-04-10T12:02:00.000Z',
      },
    ],
    approvals: [
      {
        reviewerId: 'reviewer-human-1',
        reviewerType: 'human',
        approved: true,
        role: 'maintainer',
      },
    ],
    reviewPolicy: {
      minimumApprovals: 1,
      minimumHumanApprovals: 1,
      requireHumanOnProtectedBranch: true,
    },
    globalVerification: {
      requiredChecks: ['gnosis:test', 'verification-mcp:typecheck'],
    },
  };
}

describe('agent swarm contract kernel', () => {
  it('matches path scopes with glob segments', () => {
    expect(
      pathMatchesScope(
        'open-source/gnosis/src/runtime/agent-swarm-contract.ts',
        'open-source/gnosis/src/runtime/**'
      )
    ).toBe(true);
    expect(
      pathMatchesScope(
        'apps/verification-mcp/src/handler.ts',
        'apps/*/src/*.ts'
      )
    ).toBe(true);
    expect(
      pathMatchesScope(
        'apps/verification-mcp/src/nested/handler.ts',
        'apps/*/src/*.ts'
      )
    ).toBe(false);
  });

  it('returns merge-ready with a reproducible certificate when all custody checks pass', () => {
    const result = evaluateAgentSwarmContract(createBaseRequest());

    expect(result.decision).toBe('merge-ready');
    expect(result.audit.selfConsistent).toBe(true);
    expect(result.certificate.contractDigest).toHaveLength(64);
    expect(result.certificate.traceDigest).toHaveLength(64);
    expect(result.metrics.completedTaskCount).toBe(2);
    expect(result.metrics.humanApprovalCount).toBe(1);
    expect(result.witness.verificationCustodySatisfied).toBe(true);
  });

  it('escalates when same-owner overlap and reviewer quorum friction remain bounded', () => {
    const request = createBaseRequest();
    request.taskContracts = [
      {
        ...request.taskContracts[0],
        id: 'runtime-a',
        allowPathOverlapWith: [],
      },
      {
        ...request.taskContracts[1],
        id: 'runtime-b',
        owner: 'runtime',
        title: 'Second runtime branch',
        allowedPathScopes: ['open-source/gnosis/src/runtime/**'],
        allowedTools: ['apply_patch'],
        requiredVerifications: [],
        requiresHumanReview: false,
      },
    ];
    request.taskExecutions = [
      {
        ...request.taskExecutions[0],
        taskId: 'runtime-a',
        touchedPaths: ['open-source/gnosis/src/runtime/shared.ts'],
      },
      {
        ...request.taskExecutions[1],
        taskId: 'runtime-b',
        touchedPaths: ['open-source/gnosis/src/runtime/shared.ts'],
        toolsUsed: ['apply_patch'],
        verificationResults: [],
      },
    ];
    request.approvals = [];
    request.globalVerification = { requiredChecks: ['gnosis:test'] };

    const result = evaluateAgentSwarmContract(request);

    expect(result.decision).toBe('escalate');
    expect(
      result.issues.some((issue) => issue.code === 'unauthorized_overlap')
    ).toBe(true);
    expect(
      result.issues.some((issue) => issue.code === 'missing_human_approval')
    ).toBe(true);
    expect(
      result.issues.some((issue) => issue.code === 'unauthorized_overlap')
    ).toBe(true);
  });

  it('rejects when path scope, tool scope, provenance, and verification drift fail closed', () => {
    const request = createBaseRequest();
    request.taskExecutions = [
      {
        ...request.taskExecutions[0],
        touchedPaths: ['apps/verification-mcp/src/handler.ts'],
        toolsUsed: ['apply_patch', 'bash'],
        traceId: null,
        traceDigest: null,
        verificationResults: [{ id: 'gnosis:test', status: 'failed' }],
      },
      request.taskExecutions[1],
    ];

    const result = evaluateAgentSwarmContract(request);

    expect(result.decision).toBe('reject');
    expect(
      result.issues.some((issue) => issue.code === 'path_scope_violation')
    ).toBe(true);
    expect(
      result.issues.some((issue) => issue.code === 'tool_scope_violation')
    ).toBe(true);
    expect(result.issues.some((issue) => issue.code === 'missing_trace')).toBe(
      true
    );
    expect(
      result.issues.some((issue) => issue.code === 'failed_task_verification')
    ).toBe(true);
  });

  it('detects certificate tampering during audit', () => {
    const result = evaluateAgentSwarmContract(createBaseRequest());
    const tampered = {
      ...result.certificate,
      decision: 'merge-ready' as const,
      witness: {
        ...result.certificate.witness,
        reviewerQuorumSatisfied: false,
      },
    };

    const audit = auditAgentSwarmCertificate(tampered);

    expect(audit.selfConsistent).toBe(false);
    expect(
      audit.issues.some((issue) =>
        issue.includes('Certificate witness does not match')
      )
    ).toBe(true);
  });
});
